{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the pelvic CT volume from the 'Input CT Volume' drop-down.",
      "detailed": "The pelvic CT scan provides the 3D anatomical data needed for fracture segmentation and reduction planning. Selecting the correct volume allows the software to process the anatomy of interest."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "This step automatically segments the pelvic bone from the CT volume, creating a mask that will be used as a reference for fracture alignment and screw planning."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "This step identifies and isolates individual fracture fragments from the pelvic bone. Each fragment is separated for independent reduction."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments",
      "simple": "Uncheck any fracture fragments you want to exclude from planning.",
      "detailed": "Fragments that are not part of the surgical reduction (e.g., small or non-displaced pieces) can be excluded to simplify the view. Only fragments that need alignment should remain checked."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "This step creates a template based on the intact pelvic anatomy, serving as the target alignment for fracture reduction."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register & Reduce",
      "simple": "Click the 'Run Step 4: Register _Reduce' button.",
      "detailed": "This step automatically registers the fracture fragments to the pelvis template, simulating anatomical reduction and reconstructing the pelvic ring."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manual Adjustments?",
      "simple": "If further adjustments are needed, check the 'Manually adjust a fragment' box. Otherwise, skip to step 11.",
      "detailed": "After automated reduction, you can fine-tune individual fragment positions. If the reduction is already satisfactory, proceed directly to screw planning."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment",
      "simple": "In the 'Fragment' selection box, choose the fragment you want to adjust.",
      "detailed": "Select the specific fracture fragment that requires manual repositioning to achieve an optimal anatomical fit."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment",
      "simple": "Use the transform widget to reposition and rotate the selected fragment.",
      "detailed": "Fine-tune the fragment's location and orientation to perfect alignment. Visual feedback in the 3D view confirms proximity to adjacent bone surfaces."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Adjustments",
      "simple": "Click the 'Apply adjustments' button.",
      "detailed": "Saves the manual adjustments and updates the reduction plan with the refined fragment position."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screws",
      "simple": "Click the 'Run Step 5: Plan Screws' button.",
      "detailed": "This step automatically generates optimal screw trajectories for pelvic fracture fixation, considering bone corridors and safety margins."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories?",
      "simple": "If you need to modify the screw paths, check the 'Edit Screw trajectories' box. Otherwise, the planning is complete.",
      "detailed": "Automatically planned screws may be adjusted to avoid critical structures or improve bone purchase. Selecting 'No' finalizes the plan."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform widget to reposition and rotate the screw trajectories.",
      "detailed": "Fine-tune entry point, direction, and depth of each screw for optimal fixation. Visualize the paths relative to bone and fracture lines."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws",
      "simple": "Click the 'Regenerate screws from edited lines' button.",
      "detailed": "Updates the screw plan to reflect manually adjusted trajectories, ensuring accurate screw lengths and orientations for the final guide."
    },
    {
      "step_id": "cb_step_15",
      "title": "Disable Edit Mode",
      "simple": "Uncheck the 'Edit Screw trajectories' checkbox to exit edit mode.",
      "detailed": "Finalizes screw planning. The plan is now ready for review and export."
    }
  ]
}
